const text =
  $json.text ||
  $json.output ||
  $json.response ||
  $json.message ||
  "";

const clientMatch = text.match(/CLIENT_MESSAGE:\s*([\s\S]*?)\s*SALES_MESSAGE:/i);
const salesMatch = text.match(/SALES_MESSAGE:\s*([\s\S]*)/i);

return [
  {
    json: {
      client_message: clientMatch ? clientMatch[1].trim() : text.trim(),
      sales_message: salesMatch ? salesMatch[1].trim() : "Aucun message interne généré."
    }
  }
];
